SET academy_metadata = '{"displayName":"Canada – Study Permit Extension","shortDescription":"IRCC study permit extension · In Canada · Continue studies · Maintain status","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Intermediate","learningMinutes":16,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current study permit extension fee, proof of funds amounts, and maintained status instructions on canada.ca before filing."},"alert":{"title":"Apply before permit expiry","body":"A study permit extension is deadline-driven. Late files may require restoration and can interrupt study and work authorization."},"tags":[{"label":"Active service","variant":"success"},{"label":"In-Canada only","variant":"warning"},{"label":"6–12 weeks","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"6–12 weeks processing","variant":"neutral"},{"label":"CAD $150 approx","variant":"neutral"},{"label":"Maintain student status","variant":"success"},{"label":"Expiry critical","variant":"warning"}],"kpis":[{"label":"Processing time","value":"6–12w","sub":"Check IRCC weekly","tone":"primary"},{"label":"Government fee","value":"CAD $150","sub":"Verify on canada.ca","tone":"warning"},{"label":"Our approval rate","value":"91%","sub":"~84% benchmark","tone":"success"},{"label":"Required docs","value":"11","sub":"+ enrolment proof","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"Extension for students already in Canada who need more time on their study permit to continue or complete an eligible program at a Designated Learning Institution."},{"label":"Eligible applicants","value":"In Canada · Current study permit · Continuing studies or new DLI/program · Proof of funds · Applying before expiry where possible"},{"label":"Maintained status","value":"If filed before expiry, the client may remain in Canada while IRCC processes the extension under maintained status. Study and work rights depend on previous permit conditions.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"Review new expiry date, study and work conditions, DLI obligations, and passport validity for the next extension or PGWP planning."}],"eligibility":[{"criterion":"Client is physically in Canada","met":true},{"criterion":"Current study permit is valid or client is within restoration period","met":true,"note":"Expiry date drives urgency"},{"criterion":"Continues at a DLI or has valid new LOA from DLI","met":true},{"criterion":"Proof of enrolment or transcript shows active study progress","met":true},{"criterion":"Proof of funds covers tuition, living costs, and return transport","met":true},{"criterion":"Passport valid beyond requested extension period","met":true},{"criterion":"No unauthorized work or study history","met":true},{"criterion":"Medical exam completed if IRCC profile requires it","met":false},{"criterion":"Academic gaps, program changes, or delayed completion explained","met":true}],"redFlagsBanner":"If the permit has already expired, stop and assess restoration before advising the client to keep studying or working.","redFlags":[{"title":"Permit already expired","description":"Client missed extension deadline and may have lost study/work authorization.","fix":"Assess restoration eligibility and stop unauthorized activities until resolved","severity":"High"},{"title":"Weak enrolment proof","description":"No current enrolment letter, transcript, or evidence of continued studies.","fix":"Request current DLI letter showing program, status, and expected completion","severity":"Common"},{"title":"Unexplained program delay","description":"Repeated withdrawals, failed terms, or long gaps without explanation.","fix":"Prepare timeline and supporting DLI notes before submission","severity":"Common"},{"title":"Insufficient funds","description":"Bank balance does not cover tuition and living costs or has unexplained deposits.","fix":"Add sponsor proof, tuition receipt, bank history, and source explanation","severity":"Very common"},{"title":"Passport expires soon","description":"Permit cannot usually be issued beyond passport validity.","fix":"Renew passport before extension where time permits","severity":"Medium"},{"title":"Unauthorized work","description":"Client worked beyond permitted conditions or while not eligible.","fix":"Escalate for admissibility and disclosure strategy before filing","severity":"High"},{"title":"Changed DLI without records","description":"Program or institution changed but client lacks updated LOA or transfer proof.","fix":"Collect updated LOA and explain study pathway clearly","severity":"Common"}],"faqs":[{"q":"When should the extension be filed?","a":"File before the current permit expires. IRCC often recommends applying at least 30 days before expiry, but earlier is better when documents are ready."},{"q":"Can the student keep studying after applying?","a":"If they applied before expiry and continue meeting permit conditions, they may be covered by maintained status while IRCC processes the extension."},{"q":"Can the student work while waiting?","a":"Work rights depend on the prior permit conditions and maintained status rules. Confirm before advising the client to continue work."},{"q":"What if the permit expired?","a":"Assess restoration eligibility immediately. The client may need to stop studying or working until status is restored."},{"q":"Is a new LOA required?","a":"Use a new LOA for a new program or DLI. For continuing students, current enrolment proof and expected completion date are usually important."},{"q":"How much money should be shown?","a":"Use current IRCC financial requirements plus unpaid tuition and living costs. Explain large deposits and sponsor sources."},{"q":"Does changing schools affect the extension?","a":"It can. Collect updated DLI evidence and ensure the client complied with IRCC rules for school changes."},{"q":"Can family members extend too?","a":"Dependants may need separate visitor, study, or work extensions. Screen each status independently."},{"q":"Is biometrics required again?","a":"Often biometrics remain valid for 10 years for temporary residence, but verify the client''s biometrics status and IRCC instructions."},{"q":"Will extension approval help PGWP later?","a":"It can support continuous lawful study, but PGWP eligibility depends on DLI, program, full-time status, and completion rules."},{"q":"What is Description for this service?","a":"Extension for students already in Canada who need more time on their study permit to continue or complete an eligible program at a Designated Learning Institution."},{"q":"What is Eligible applicants for this service?","a":"In Canada · Current study permit · Continuing studies or new DLI/program · Proof of funds · Applying before expiry where possible"},{"q":"What is Maintained status for this service?","a":"If filed before expiry, the client may remain in Canada while IRCC processes the extension under maintained status. Study and work rights depend on previous permit conditions."},{"q":"Important note on Maintained status?","a":"If filed before expiry, the client may remain in Canada while IRCC processes the extension under maintained status. Study and work rights depend on previous permit conditions."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Review new expiry date, study and work conditions, DLI obligations, and passport validity for the next extension or PGWP planning."},{"q":"Is Client is physically in Canada required?","a":"Client is physically in Canada is typically required."},{"q":"Is Current study permit is valid or client is within restoration period required?","a":"Expiry date drives urgency"},{"q":"Is Continues at a DLI or has valid new LOA from DLI required?","a":"Continues at a DLI or has valid new LOA from DLI is typically required."},{"q":"Is Proof of enrolment or transcript shows active study progress required?","a":"Proof of enrolment or transcript shows active study progress is typically required."},{"q":"Is Proof of funds covers tuition, living costs, and return transport required?","a":"Proof of funds covers tuition, living costs, and return transport is typically required."},{"q":"Is Passport valid beyond requested extension period required?","a":"Passport valid beyond requested extension period is typically required."},{"q":"Is No unauthorized work or study history required?","a":"No unauthorized work or study history is typically required."},{"q":"Is Medical exam completed if IRCC profile requires it required?","a":"Assess whether Medical exam completed if IRCC profile requires it is satisfied for this case."},{"q":"Is Academic gaps, program changes, or delayed completion explained required?","a":"Academic gaps, program changes, or delayed completion explained is typically required."},{"q":"What is the Processing time?","a":"6–12w — Check IRCC weekly"},{"q":"What is the Government fee?","a":"CAD $150 — Verify on canada.ca"},{"q":"What is the Our approval rate?","a":"91% — ~84% benchmark"},{"q":"What is the Required docs?","a":"11 — + enrolment proof"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}],"compliance":["Client service agreement and consent must be on file before submission","Never advise unauthorized work or study while status is uncertain","Never guarantee study permit extension approval","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Start extension review 90 days before permit expiry","Ask for current enrolment letter with expected completion date","Match requested extension length to academic plan and passport validity","Explain every study gap or program change in the cover letter","Check work conditions before giving maintained status advice","Keep proof of submission and fee receipt for school and employer records"],"postApproval":["Send new study permit expiry date and conditions to client","Remind client to update school and employer records if needed","Review off-campus work rules and full-time study obligations","Calendar next expiry date and expected completion date","Discuss PGWP planning if program is near completion"],"performance":{"ourRate":91,"industryRate":84,"stats":[{"label":"Files this year","value":"96"},{"label":"Approved","value":"87"},{"label":"Refused","value":"6"},{"label":"Withdrawn","value":"3"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":91,"benchmark":84},{"label":"Timely filing","ours":95,"benchmark":82},{"label":"Academic continuity","ours":89,"benchmark":77},{"label":"Financial documentation","ours":88,"benchmark":75}],"timeline":[{"weeks":"1","title":"Expiry, enrolment, and status screening"},{"weeks":"1–2","title":"DLI letters, financials, and explanation prep"},{"weeks":"2","title":"Portal submission and fee payment"},{"weeks":"6–12","title":"IRCC processing and maintained status monitoring"}],"relatedServices":[{"label":"Canada – Student Visa","libraryId":""},{"label":"Canada – PGWP","libraryId":""},{"label":"Canada – Visitor Record","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial study permit extension counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Prioritize expiry date, active enrolment, study continuity, and funds. Escalate expired status or unauthorized work."}],"resources":[{"title":"IRCC — Extend your study permit","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/extend-study-permit.html","description":"Official extension instructions"},{"title":"IRCC — Study permit conditions","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit/while-you-study.html","description":"Rules while studying in Canada"},{"title":"IRCC — Change schools or programs","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/change-schools.html","description":"Instructions for DLI or program changes"},{"title":"IRCC — Restore status as a student","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/extend-study-permit/restore-status.html","description":"Restoration guidance if status expired"},{"title":"IRCC — Processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current study permit extension estimates"},{"title":"IRCC — Pay your fees","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/pay-fees.html","description":"Current study permit fee page"}],"quiz":[{"level":1,"question":"In a study permit extension from inside Canada, which statement about who needs an extension is correct?","options":["A student needs an extension if their study permit will expire before they finish authorized studies in Canada.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The permit expiry must cover the period of study and any authorized stay."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about where the application is made is correct?","options":["A study permit extension is normally submitted from inside Canada before the current permit expires.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Inside-Canada extension rules differ from an outside-Canada study permit application."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about maintained status is correct?","options":["If a complete extension is submitted before expiry, the student can usually keep studying under the old conditions while waiting.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Maintained status protects temporary resident status during processing."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about extension fee is correct?","options":["The standard study permit extension processing fee is CAD $150.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"This is the same base fee as many study permit applications, separate from other possible costs."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about completion letter is correct?","options":["A completion letter is not required just to extend a study permit before studies are completed.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Extension evidence usually focuses on current enrolment, remaining studies, and funds."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about proof of enrolment is correct?","options":["Current enrolment or registration evidence helps show the student is actively pursuing studies.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC needs proof the student remains a genuine student."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about transcripts is correct?","options":["Transcripts or academic records can show progress and compliance with study conditions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Academic progress supports the need for more time."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about passport validity is correct?","options":["The new study permit cannot normally be issued beyond the passport expiry date.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A short passport can shorten the extension."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about DLI status is correct?","options":["The student should remain enrolled at a designated learning institution for post-secondary studies.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"DLI compliance is central to maintaining study permit eligibility."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about financial proof is correct?","options":["The student must show enough money to continue paying tuition and living expenses.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Inside-Canada applicants still need credible financial support."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about applying after expiry is correct?","options":["After expiry, a student may need restoration and cannot rely on maintained status if no timely application was filed.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Restoration is different from a timely extension."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about restoration period is correct?","options":["Restoration is generally available only within 90 days of losing status and if the person remains eligible.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Restoration is discretionary and does not authorize study while pending unless rules allow."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about TRV distinction is correct?","options":["A study permit extension does not automatically renew a TRV counterfoil for travel.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Status documents and entry visas are different documents."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about co-op conditions is correct?","options":["A student needing mandatory co-op work may require a co-op work permit in addition to the study permit.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Study authorization does not always cover required work placements."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about part-time study is correct?","options":["Dropping to part-time can affect work authorization and may raise compliance questions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Full-time status often matters for work privileges and future benefits."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about authorized leave is correct?","options":["Approved leave should be documented if it affects enrolment or progress.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC may ask why studies were interrupted."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about program extension is correct?","options":["A school letter showing the new expected completion date supports the need for a longer permit.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The extension length should match remaining studies."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about conditions on permit is correct?","options":["Students must follow printed and implied conditions, including school and work restrictions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Non-compliance can affect extensions and future applications."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about biometrics is correct?","options":["Biometrics may be required if not already valid or exempt, depending on IRCC instructions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Inside-Canada biometrics rules can still apply."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about medical exam is correct?","options":["A medical may be needed for certain programs, work settings, or if IRCC requests it.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Medical admissibility can still matter inside Canada."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about family members is correct?","options":["Accompanying family may need their own status extensions tied to the student''s situation.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Each person must maintain valid status in Canada."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about program changes is correct?","options":["Changing programs can be acceptable if the student remains compliant and evidence explains the path.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC reviews whether the student is genuinely progressing."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about PGWP timing is correct?","options":["Students should not confuse a study permit extension with a post-graduation work permit application.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A PGWP is normally sought after program completion, not as a study extension."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about expiry date awareness is correct?","options":["Students are responsible for tracking the permit expiry date even if the school program continues.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A valid enrolment letter does not extend status automatically."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about online account notices is correct?","options":["IRCC communicates requests and decisions through the online account or portal used for submission.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Missing a document request can cause refusal."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about IMM 5709?","options":["IMM 5709 is the main form used to change conditions, extend stay, or remain in Canada as a student.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"It is the standard inside-Canada study permit extension form."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about timely filing?","options":["The application should be submitted before the current study permit expires to preserve maintained status.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The submission timestamp matters for status continuity."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about enrolment letter?","options":["A current enrolment letter should show program, DLI, student status, and expected completion date.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"This is stronger evidence than an old admission letter alone."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about academic transcript?","options":["A transcript helps document progress, course load, and compliance with study conditions.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC may use it to assess whether the student has actively studied."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about financial uploads?","options":["Recent bank statements, scholarship letters, sponsor proof, or tuition receipts can prove continued funds.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Funds must support the remaining stay, not only the original admission."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about passport upload?","options":["The passport bio page and stamped pages are commonly uploaded to confirm identity and validity.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Passport expiry affects permit length."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about digital photo?","options":["A compliant digital photo may be required as part of the online checklist.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Photo specifications are part of application completeness."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about biometrics request?","options":["If biometrics are required, IRCC will issue instructions and a deadline after submission.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Failure to complete biometrics can lead to refusal or delay."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about medical request?","options":["If IRCC requests a medical, the student must use a panel physician and meet the deadline.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Medical requests are formal processing steps."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about client information letter?","options":["A cover letter can explain delays, program changes, reduced course load, or funding details.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Clear explanation helps the officer understand non-standard facts."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about changing conditions?","options":["Students can request changes such as school or work-related conditions when supported by evidence.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The request should match eligibility and documents."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about co-op work permit add-on?","options":["If co-op is mandatory, the student should include school confirmation that work is required for the program.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Mandatory work placements need separate authorization in many cases."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about family extension timing?","options":["Family members should apply to extend their own records before expiry, often together with the student.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Maintained status is personal to each applicant''s timely filing."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about TRV renewal after extension?","options":["After receiving the extended study permit, a visa-required student may apply separately for a new TRV if travel is needed.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A TRV is for re-entry and is not the same as status in Canada."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about proof of continued DLI enrolment?","options":["The extension package should show the student is still at a DLI and actively registered.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"DLI compliance supports both eligibility and genuineness."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about processing while waiting?","options":["During maintained status, the student should avoid leaving Canada unless they understand the effect on re-entry and study authorization.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Travel can complicate maintained status and re-entry."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about refusal while on maintained status?","options":["If the extension is refused, maintained status ends on the refusal date.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The student must then assess restoration or departure options quickly."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about restoration application?","options":["A restoration request must include restoration fees, the study permit request, and an explanation of lost status.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Restoration is not just a late extension form."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about program deferral evidence?","options":["If studies are delayed, the student should include deferral or revised completion documents from the school.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC needs evidence explaining why more time is needed."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about authorized leave records?","options":["School-approved leave letters can explain gaps without making the file look abandoned.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Documented leave is better than unexplained inactivity."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about form consistency?","options":["Dates in IMM 5709 should match passport entries, school letters, and previous permit details.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Inconsistencies can create credibility or processing concerns."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about uploading old LOA?","options":["An old LOA alone is usually weaker than current enrolment and expected completion evidence.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Extensions are based on continuing studies, not only initial admission."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about payment receipt?","options":["The IRCC receipt should show the correct study permit extension fee and any other required fees.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Incorrect fees can affect completeness."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about document request deadline?","options":["Additional document requests must be answered by the stated deadline or an extension requested if available.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Missed deadlines can result in refusal."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about approval document review?","options":["After approval, the student should check name, expiry date, school conditions, and work remarks on the new permit.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Errors should be addressed promptly."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with applying one day late?","options":["The student may have lost status and cannot claim maintained status from a late extension.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Timely filing is the foundation for maintained status."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with studying after status expired?","options":["Unauthorized study after expiry can create compliance problems for restoration and future applications.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A late applicant must be careful about activities while out of status."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with no academic progress?","options":["Repeated failures, withdrawals, or unexplained gaps may make the officer doubt genuine study compliance.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Extensions require a credible reason for needing more time."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with completion letter confusion?","options":["Asking for an extension after completion may be inappropriate if the person should be pursuing PGWP or visitor status instead.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A completion letter is not required for an in-progress extension, but completion changes the strategy."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with short passport validity?","options":["A short passport can produce a short permit and force another extension soon.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"IRCC generally cannot issue the permit beyond passport expiry."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with leaving Canada on maintained status?","options":["Travel can end the practical benefit of maintained status and create re-entry complications.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Students should understand that maintained status is tied to remaining in Canada."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with working too many hours?","options":["Work-condition violations can undermine the extension and later PGWP eligibility.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers consider whether the student complied with permit conditions."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with part-time semesters?","options":["Unexplained part-time study can raise concerns about work authorization and genuine student status.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Documentation of authorized leave or final-term exceptions may be important."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with school losing DLI status?","options":["If the institution is no longer a DLI, the student may need to transfer or explain eligibility carefully.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"DLI status is a threshold issue for study permit holders."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with program hopping?","options":["Frequent unexplained program changes can look like the student is prolonging stay rather than studying.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A coherent academic path reduces officer concern."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with insufficient funds after years in Canada?","options":["Weak current funds can cause refusal even if the original study permit was approved.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Extensions are assessed on present ability to support the stay."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with unpaid tuition balance?","options":["Large unpaid balances may suggest the student cannot continue studies.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office 