ages."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with unauthorized school transfer?","options":["Failure to follow DLI change rules can appear as non-compliance in an extension review.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"School changes should be handled through IRCC''s required process."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with gap caused by illness?","options":["A medical or personal gap should be documented rather than left unexplained.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Evidence can turn a red flag into an understandable circumstance."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with officer weighing discretion?","options":["The officer looks for lawful status, genuine continued study, sufficient funds, and compliance with past conditions.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A strong extension file answers all four themes clearly."}],"donts":{"dos":["File before the current permit expires whenever possible","Collect current enrolment proof and transcript","Show credible funds for tuition and living costs","Explain program changes and study gaps","Calendar the new expiry date after approval"],"donts":["Do not advise work if status is uncertain","Do not file with expired enrolment evidence","Do not ignore restoration if permit expired","Do not promise approval or exact processing time","Do not overlook passport expiry"],"mistakes":["Applying after expiry without restoration forms","Missing DLI enrolment letter","Unexplained failed terms or withdrawals","Weak bank history with recent deposits","Requesting extension beyond passport validity"]},"sampleDocs":[{"title":"Sample passport bio page (mock)","description":"Identity page with passport validity visible.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample current study permit (mock)","description":"Shows permit conditions and expiry date.","mimeType":"application/pdf","docKind":"identity"},{"title":"Sample enrolment letter (mock)","description":"DLI confirmation of active enrolment and expected completion.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample transcript (mock)","description":"Academic progress evidence for extension review.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample tuition receipt (mock)","description":"Paid tuition or outstanding fee statement.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample bank statement (mock)","description":"Recent bank history with balance and account holder name.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample sponsor affidavit (mock)","description":"Sponsor commitment with source of income support.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample explanation letter (mock)","description":"Explains delayed completion, program change, or study gap.","mimeType":"application/pdf","docKind":"academic"}],"navBucket":"visa","workingRights":{"applicant":{"summary":"Study permit holders may work on-campus anytime. Off-campus work is allowed up to 24 hours per week during regular academic sessions and full-time during scheduled breaks, subject to permit conditions.","details":["Co-op work requires a co-op work permit in addition to study permit.","Work must not start before permit conditions allow — verify printed remarks.","PGWP is a separate application after eligible program completion."],"restrictions":["Cannot work for ineligible employers if restricted on permit","Must remain enrolled and making progress at DLI"],"sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/work.html","lastVerified":"Jun 2026"},"spouse":{"summary":"Spouse/common-law partner may qualify for an open work permit (SOWP) when the student is in an eligible program at a designated learning institution in Canada.","details":["Eligibility depends on program level, duration, and current IRCC policy for SOWP.","Partner applies separately; relationship and principal status must be documented."],"restrictions":["Not automatic — assess program eligibility before promising spouse work rights"],"sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada/special-instructions/spousal.html","lastVerified":"Jun 2026"}},"fullCostBreakdown":{"title":"Full cost breakdown — Canada – Study Permit Extension","currency":"CAD","lastVerified":"Jun 2026","disclaimer":"Indicative costs for counselor discussions only. Government fees, tuition, and living amounts change — verify on official websites before quoting clients. Exchange rates affect INR equivalents.","sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship.html","sections":[{"id":"fees","label":"Government & visa fees","items":[{"label":"Study permit application","amount":235,"unit":"per applicant","currency":"CAD","applicable":true},{"label":"Biometrics","amount":85,"unit":"per applicant","currency":"CAD","applicable":true},{"label":"Medical exam (if required)","range":"INR 5,000–8,000","notes":"Panel physician","currency":"CAD","applicable":true}]},{"id":"tuition","label":"Tuition & education costs","items":[{"label":"Tuition (undergraduate, indicative)","range":"Mid-range for destination","notes":"Use offer letter amount","currency":"CAD","applicable":true},{"label":"Tuition deposit already paid","range":"Per LOA/CAS","notes":"Deduct from total funds","currency":"CAD","applicable":true},{"label":"Books & materials","range":"500–1,500","unit":"per year","notes":"Program dependent","currency":"CAD","applicable":true}]},{"id":"living","label":"Living costs","items":[{"label":"Living funds (IRCC guideline, 1 person)","amount":20635,"unit":"per year","notes":"Outside Quebec","currency":"CAD"},{"label":"Accommodation","range":"700–1,400","unit":"per month","currency":"CAD"},{"label":"Food & personal","range":"300–550","unit":"per month","currency":"CAD"}]},{"id":"misc","label":"Miscellaneous","items":[{"label":"Future Link consultancy fee","range":"See Fees tab","notes":"Service package dependent"},{"label":"Flight / travel","range":"₹40,000–1,20,000","notes":"Season and route"},{"label":"Document translation / notary","range":"₹2,000–15,000"},{"label":"Courier & VFS premium services","range":"Optional"},{"label":"Forex / transfer charges","range":"Bank dependent","notes":"GIC, blocked account, tuition transfers"}]}],"totals":[{"label":"Indicative first-year budget (excl. tuition band)","value":"Counselor to calculate from sections above","notes":"Always cross-check LOA/CAS/Offer of Place and official fee pages before client commitment."}]}}'::jsonb, updated_at = now()
